INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Portfolio', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'A curated collection of creative work', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the project name followed by a dash and the client, medium, or context. Keep it scannable from a grid thumbnail."},"content":{"tips":"Write as a case study: what was the challenge, how did you approach it, and what was the outcome. Structure for skimming."},"formatting":["Headings: separate Challenge, Process, Result, and Tools sections","Bullet lists: deliverables, tools used, key metrics","Bold: highlight standout outcomes or client quotes","Tables: project specs (timeline, tools, dimensions, file formats)","Paragraphs: narrative context and creative rationale"],"avoid":["Vague descriptions without specific outcomes","Listing only tools without explaining the creative process","Missing project context or client brief summary"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":150},"content":{"min":50,"max":15000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
